// =============================================================
// Resolve and Build Email Payload
// =============================================================
// Single Code node implements the simpler 4-step flow:
// Extract Input → Fetch Email Template → Resolve Variables →
// Substitute Bindings. Uses supabaseRequest() for the template
// lookup (template_id is the user's explicit choice). Recipient
// must come from to_expression (literal or {{variable}}) — handlers
// consume from variableContext, never re-fetch derived data.
// =============================================================

const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// @inline supabase-request
async function supabaseRequest(path, method, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

function resolveVariables(template, context) {
  if (typeof template !== 'string') return template;
  return template.replace(/\{\{(\s*[\w.]+\s*)\}\}/g, (_, rawKey) => {
    const key = rawKey.trim();
    const value = getNestedValue(context, key);
    return (value !== undefined && value !== null) ? String(value) : `{{${key}}}`;
  });
}

function getNestedValue(obj, path) {
  const parts = path.split('.');
  let current = obj;
  for (const part of parts) {
    if (current === null || current === undefined || typeof current !== 'object') return undefined;
    current = current[part];
  }
  return current;
}

try {
  const item = $input.first().json;
  const { resolvedConfig, variableContext, tenantId } = item;

  const templateId = resolvedConfig.template_id || null;
  const configuredTo = resolvedConfig.to_expression || null;
  const configuredSubject = resolvedConfig.subject || 'Notification';
  const configuredHtml = resolvedConfig.html_body || '<p>Notification</p>';

  // ---- Fetch email template (template_id is the user's explicit choice) ----
  const results = {};
  if (templateId) {
    results.template = await supabaseRequest(
      `email_templates?id=eq.${templateId}&tenant_id=eq.${encodeURIComponent(tenantId ?? '00000000-0000-0000-0000-000000000000')}&limit=1`, 'GET'
    );
  }

  // ---- Merge template data ----
  let subject = configuredSubject;
  let html = configuredHtml;

  if (results.template && results.template.length > 0) {
    const tpl = results.template[0];
    if (tpl.subject) subject = tpl.subject;
    if (tpl.html_body) html = tpl.html_body;
  }

  // ---- Resolve recipient ----
  // Recipient comes from to_expression only. Orchestrator's Prepare Current Step
  // already substituted any {{variables}} from variableContext. Handlers must not
  // re-fetch derived data (e.g. survey_links.notification_email) — that's a workflow
  // authoring concern, surfaced via {{getResponse.*}} or a literal value.
  const to = configuredTo;

  // Detect unresolved variable literals — clearer error than letting Resend reject.
  // Example: configured to_expression="{{getResponse.clientEmail}}" but clientEmail was null
  // → resolveVariables left the literal in place. Surface this as a config issue, not a send error.
  if (to && /\{\{[^}]+\}\}/.test(to)) {
    throw new Error(`Recipient expression contains unresolved variable: "${to}". Check that the referenced variable is populated by an earlier step, or pick a different source.`);
  }

  if (!to) throw new Error('Recipient is required for send_email step. Set to_expression to a literal email address (e.g. user@example.com) or a workflow variable that resolves to an email (e.g. {{getResponse.clientEmail}}).');

  // ---- Resolve variable_bindings against variableContext ----
  // Each binding maps a template variable key to a workflow expression like {{step1.clientName}}.
  // resolveVariables() substitutes the expression value from variableContext.
  const bindings = resolvedConfig.variable_bindings || {};
  const resolvedBindings = {};
  for (const [templateVar, expression] of Object.entries(bindings)) {
    resolvedBindings[templateVar] = resolveVariables(String(expression), variableContext);
  }

  // ---- Substitute bindings into subject and html ----
  // Uses simple key lookup — only substitutes variables that have explicit bindings.
  // Unbound {{var}} placeholders stay as-is (visible in email — signals misconfiguration).
  function substituteBindings(template, bindings) {
    return template.replace(/\{\{(\s*[\w]+\s*)\}\}/g, (match, rawKey) => {
      const key = rawKey.trim();
      return Object.prototype.hasOwnProperty.call(bindings, key) ? bindings[key] : match;
    });
  }

  subject = substituteBindings(subject, resolvedBindings);
  html = substituteBindings(html, resolvedBindings);

  return {
    json: {
      ...item,
      emailPayload: { to, subject, html, tenant_id: tenantId },
    }
  };

} catch (err) {
  const item = $input.first().json;
  return {
    json: {
      ...item,
      stepResult: { success: false, error: err.message },
    }
  };
}

// Pass through error result — preserve orchestrator context
const item = $input.first().json;
return {
  json: {
    ...item,
  }
};

// Flatten emailPayload to top level for Send Email subworkflow
// Send Email expects { to, subject, html, tenant_id }
const item = $input.first().json;
const { to, subject, html, tenant_id } = item.emailPayload;
return { json: { to, subject, html, tenant_id } };

// =============================================================
// Save Input Payload — audit per attempt (T-209)
// =============================================================
// Save rendered ready-to-execute payload BEFORE external call.
// Each retry attempt produces a fresh render via this same path.
// (Reuse cached input_payload on retry — planowany jako follow-up task.)
// =============================================================

const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

