}
// @end-inline supabase-request

const item = $input.first().json;
// Send Email handler: items here have flat { to, subject, html, tenant_id } shape
// (post Flatten Email Payload). Need to reach back to upstream node for currentStepExecId.
// NOTE: Reach back via $('Resolve and Build Payload') for currentStepExecId because
// Flatten Email Payload (upstream) drops orchestrator context (Payload Flattening
// anti-pattern, see ag-n8n-step-handlers skill). Other 7 handlers read from item directly.
const upstream = $('Resolve and Build Payload').first().json;
const inputPayload = {
  to: item.to,
  subject: item.subject,
  html: item.html,
  tenant_id: item.tenant_id,
};

if (upstream.currentStepExecId) {
  await supabaseRequest(
    `workflow_step_executions?id=eq.${upstream.currentStepExecId}`,
    'PATCH',
    { input_payload: inputPayload }
  );
}

return { json: item };

// Handle Send Email subworkflow failure — preserve orchestrator context
const item = $('Resolve and Build Payload').first().json;
const errorData = $input.first().json;
const errorMsg = errorData.error?.message || errorData.message || 'Send Email subworkflow failed';
return {
  json: {
    ...item,
    stepResult: { success: false, error: errorMsg },
  }
};

// Build success result — preserve orchestrator context
const item = $('Resolve and Build Payload').first().json;
return {
  json: {
    ...item,
    stepResult: {
      success: true,
      outputPayload: {
        emailSent: true,
        recipientEmail: item.emailPayload.to,
      },
    },
  }
};
